mapper.insert:
INSERT INTO cm_topo_group ( grp_parent, grp_no, grp_name, user_id ) VALUES ( 0, 1, (SELECT grp_name FROM nt_cfg_group WHERE grp_parent = 0 AND grp_type = 1 LIMIT 1),
