INSERT INTO cm_topo_group ( user_id, grp_no, grp_name, grp_parent ) SELECT user_id, grp_no, grp_name, CASE WHEN (SELECT COUNT(*) FROM nt_cfg_group WHERE grp_no IN ( SELECT DISTINCT sub_no FROM nt_cfg_leaf WHERE grp_no IN ( SELECT nt_grp_no FROM com_auth_group_subgrp WHERE auth_grp_no = #{authGrpNo} ) ) AND grp_no = T1.grp_parent ) > 0 THEN grp_parent ELSE 1 END AS grp_parent FROM ( SELECT DISTINCT AS user_id, A.grp_no, A.grp_name, CASE WHEN A.grp_parent = 0 THEN 1 ELSE A.grp_parent END AS grp_parent FROM nt_cfg_group A WHERE grp_no IN ( SELECT DISTINCT sub_no FROM nt_cfg_leaf WHERE grp_no IN ( SELECT nt_grp_no FROM com_auth_group_subgrp WHERE auth_grp_no = #{authGrpNo} ) ) AND grp_parent != 0 ) T1

mapper.select:
SELECT CASE WHEN is_share = 1 THEN parent_id ELSE user_id END
FROM   com_user
WHERE  user_id = #{userId}
